#include <bits/stdc++.h>
using namespace std;

// Big integer for counting palindromes and for constructing the largest palindrome
struct BigInt {
    string s; // stored in reverse (least significant first)
    BigInt() : s("0") {}
    BigInt(long long x) {
        if (x == 0) s = "0";
        else {
            s = "";
            while (x) { s.push_back('0' + (x % 10)); x /= 10; }
        }
    }
    BigInt(const string &str) {
        s = str;
        reverse(s.begin(), s.end());
    }
    void add(const BigInt &other) {
        int carry = 0;
        size_t i;
        for (i = 0; i < s.size() || i < other.s.size() || carry; ++i) {
            if (i >= s.size()) s.push_back('0');
            int sum = (s[i] - '0') + (i < other.s.size() ? other.s[i] - '0' : 0) + carry;
            carry = sum / 10;
            s[i] = '0' + (sum % 10);
        }
    }
    void multiply(long long x) {
        if (x == 0) { s = "0"; return; }
        long long carry = 0;
        for (size_t i = 0; i < s.size() || carry; ++i) {
            if (i >= s.size()) s.push_back('0');
            long long prod = (s[i] - '0') * x + carry;
            s[i] = '0' + (prod % 10);
            carry = prod / 10;
        }
    }
    void divide(long long x) {
        if (x == 0) return;
        string res;
        long long rem = 0;
        for (int i = (int)s.size() - 1; i >= 0; --i) {
            rem = rem * 10 + (s[i] - '0');
            res.push_back('0' + (rem / x));
            rem %= x;
        }
        // remove leading zeros
        size_t pos = res.find_first_not_of('0');
        if (pos == string::npos) {
            s = "0";
        } else {
            res = res.substr(pos);
            reverse(res.begin(), res.end());
            s = res;
        }
    }
    string to_string() const {
        string t = s;
        reverse(t.begin(), t.end());
        return t;
    }
};

BigInt fact[21]; // factorials up to 20! (max half length = 20)

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string num;
    cin >> num;

    // Count digit frequencies
    int freq[10] = {0};
    for (char c : num) {
        freq[c - '0']++;
    }

    // total half length = n/2
    int n = (int)num.size();
    int half = n / 2;

    // Precompute factorials
    fact[0] = BigInt(1);
    for (int i = 1; i <= half; ++i) {
        fact[i] = fact[i-1];
        fact[i].multiply(i);
    }

    // Count distinct palindromes = (half)! / prod_over_digits (freq[d]/2)!
    // But digits that appear 0 times contribute freq[d]/2 = 0! = 1, so fine.
    BigInt count = fact[half];
    for (int d = 0; d <= 9; ++d) {
        int k = freq[d] / 2;
        if (k > 0) {
            count.divide(fact[k].to_string()); // this is hack-ish, let's just compute by dividing by k! directly using integer arithmetic
        }
    }

    // Actually let's redo count properly using long double? No, we need exact.
    // We'll compute count by multiplying/dividing stepwise to avoid big division issues.
    // Simpler: compute count as multinomial coefficient using repeated multiplication and division.
    // Re-do:
    count = BigInt(1);
    // Numerator: multiply by 1..half
    // Denominator: for each digit d, multiply by 1..(freq[d]/2)
    // We'll do count = 1; for i=2..half: count = count * i / ... 
    // Better: use factorial and division as above but implement divide(BigInt) properly.

    // Let's implement divide(BigInt) - actually we'll just do integer division by small ints.
    // Recompute cleanly:
    count = BigInt(1);
    // Multiply by 1..half
    for (int i = 2; i <= half; ++i) {
        count.multiply(i);
    }
    // Divide by (freq[d]/2)! for each d
    for (int d = 0; d <= 9; ++d) {
        int k = freq[d] / 2;
        for (int i = 2; i <= k; ++i) {
            count.divide(i);
        }
    }

    // Output count
    cout << count.to_string() << "\n";

    // Construct largest palindrome:
    // For each digit from 9 down to 0, take half of its frequency for the left half.
    string left = "";
    for (int d = 9; d >= 0; --d) {
        int k = freq[d] / 2;
        left.append(k, '0' + d);
    }
    string right = left;
    reverse(right.begin(), right.end());
    string largest = left + right;
    // Remove leading zeros (shouldn't happen because highest digit freq > 0)
    cout << largest << "\n";

    return 0;
}
